const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ args: ['--no-sandbox'] });
  const page = await browser.newPage();

  // Go to login page
  await page.goto('http://localhost:5174');
  await page.waitForLoadState('networkidle');
  console.log('TITLE:', await page.title());
  console.log('URL after load:', page.url());
  await page.screenshot({ path: '/tmp/scoot-01-landing.png' });

  // Fill login form
  const userField = await page.$('input[name="username"], input[type="text"], input[placeholder*="user" i], input[placeholder*="Username" i]');
  const passField = await page.$('input[type="password"]');
  console.log('Has username field:', !!userField);
  console.log('Has password field:', !!passField);

  if (userField && passField) {
    await userField.fill('admin');
    await passField.fill('Astros.22');
    await page.screenshot({ path: '/tmp/scoot-02-filled.png' });
    await page.keyboard.press('Enter');
    await page.waitForLoadState('networkidle');
    await page.waitForTimeout(1500);
    console.log('URL after login:', page.url());
    await page.screenshot({ path: '/tmp/scoot-03-after-login.png' });
    console.log('POST-LOGIN TITLE:', await page.title());
    const body = await page.textContent('body');
    console.log('BODY SNIPPET:', body.slice(0, 300));
  } else {
    console.log('LOGIN FORM NOT FOUND');
    const body = await page.textContent('body');
    console.log('PAGE BODY:', body.slice(0, 500));
  }

  await browser.close();
})();
EOF
