import { Router } from "express";
import { eq } from "drizzle-orm";
import { db } from "../db/index.js";
import { users, scootMembers, scoots } from "../db/schema.js";
import { getProvider } from "../llm/provider.js";
import { log } from "../log.js";

const router = Router();

const BIGMO_SYSTEM_PROMPT = `You are BigMo, the AI member of The Fonde Brotherhood — a 55+ basketball community in Houston, Texas.

You know about Scoot(34), the Brotherhood's token economy and community platform. You're warm, direct, and community-focused. You know basketball. You care about the Brothers.

Keep responses conversational and concise — this is a chat, not an essay. If you don't know something specific about a member's account, say so honestly rather than guessing.`;

// Body RC sends for outgoing webhooks
interface RCWebhookBody {
  token?: string;
  channel_id?: string;
  channel_name?: string;
  user_id?: string;
  user_name?: string;
  user_full_name?: string;
  text?: string;
  trigger_word?: string;
  bot?: boolean;
  message_id?: string;
}

router.post("/webhook", async (req, res) => {
  const body = req.body as RCWebhookBody;

  // Verify webhook token
  const expectedToken = process.env.RC_WEBHOOK_TOKEN;
  if (expectedToken && body.token !== expectedToken) {
    log.warn("RC webhook: invalid token");
    res.status(401).json({ ok: false });
    return;
  }

  // Ignore bot messages to prevent reply loops
  if (body.bot) {
    res.json({});
    return;
  }

  const rcUsername = body.user_name ?? "";
  const triggerWord = body.trigger_word ?? "@BigMo";
  const rawText = body.text ?? "";

  // Strip the trigger word and clean up the message
  const userMessage = rawText.replace(new RegExp(triggerWord, "gi"), "").trim();
  if (!userMessage) {
    res.json({ text: "Hey! What can I do for you?" });
    return;
  }

  try {
    // Look up Scoot member context by matching RC username to Scoot username
    const user = await db.query.users.findFirst({
      where: eq(users.username, rcUsername),
    });

    const systemParts: string[] = [BIGMO_SYSTEM_PROMPT];

    if (user) {
      const membership = await db
        .select({ scootName: scoots.name, role: scootMembers.role })
        .from(scootMembers)
        .innerJoin(scoots, eq(scoots.id, scootMembers.scootId))
        .where(eq(scootMembers.userId, user.id));

      const name = user.displayName ?? user.username;
      systemParts.push(`\nYou are speaking with ${name}.`);

      if (membership.length > 0) {
        const m = membership[0];
        systemParts.push(`They are a ${m.role} of ${m.scootName}.`);
      }
    } else {
      systemParts.push(`\nYou are speaking with ${rcUsername}. They don't have a Scoot account yet.`);
    }

    const provider = getProvider();
    const reply = await provider.chat(
      [{ role: "user", content: userMessage }],
      { system: systemParts.join(" ") }
    );

    res.json({ text: reply });
  } catch (err) {
    log.error({ err }, "RC webhook: LLM error");
    res.json({ text: "Sorry, I'm having trouble right now. Try again in a moment." });
  }
});

export default router;

import { Router } from "express";
import { db } from "../db/index.js";
import { scoots, scootMembers, scootPages, scootPageBlocks } from "../db/schema.js";
import { eq, and, asc } from "drizzle-orm";
import { requireAuth } from "../middleware/auth.js";

const router = Router();
router.use(requireAuth);

router.get("/", async (req, res) => {
  const userId = (req.user as { id: number }).id;
  const rows = await db
    .select({
      id: scoots.id,
      slug: scoots.slug,
      name: scoots.name,
      description: scoots.description,
      logoUrl: scoots.logoUrl,
      labelMap: scoots.labelMap,
      featureFlags: scoots.featureFlags,
      navItems: scoots.navItems,
      role: scootMembers.role,
    })
    .from(scootMembers)
    .innerJoin(scoots, eq(scootMembers.scootId, scoots.id))
    .where(eq(scootMembers.userId, userId))
    .orderBy(asc(scoots.name));
  res.json({ ok: true, data: rows });
});

router.get("/:id", async (req, res) => {
  const userId = (req.user as { id: number }).id;
  const scootId = parseInt(req.params.id);
  if (isNaN(scootId)) return res.status(400).json({ ok: false, error: "invalid id" });

  const member = await db.query.scootMembers.findFirst({
    where: and(eq(scootMembers.scootId, scootId), eq(scootMembers.userId, userId)),
  });
  if (!member) return res.status(404).json({ ok: false, error: "not found" });

  const scoot = await db.query.scoots.findFirst({ where: eq(scoots.id, scootId) });
  if (!scoot) return res.status(404).json({ ok: false, error: "not found" });

  res.json({ ok: true, data: { ...scoot, role: member.role } });
});

router.get("/:id/pages", async (req, res) => {
  const userId = (req.user as { id: number }).id;
  const scootId = parseInt(req.params.id);
  if (isNaN(scootId)) return res.status(400).json({ ok: false, error: "invalid id" });

  const member = await db.query.scootMembers.findFirst({
    where: and(eq(scootMembers.scootId, scootId), eq(scootMembers.userId, userId)),
  });
  if (!member) return res.status(404).json({ ok: false, error: "not found" });

  const pages = await db
    .select({
      id: scootPages.id,
      slug: scootPages.slug,
      title: scootPages.title,
      navLabel: scootPages.navLabel,
      navOrder: scootPages.navOrder,
    })
    .from(scootPages)
    .where(and(eq(scootPages.scootId, scootId), eq(scootPages.published, true)))
    .orderBy(asc(scootPages.navOrder), asc(scootPages.title));

  res.json({ ok: true, data: pages });
});

router.get("/:id/pages/:slug", async (req, res) => {
  const userId = (req.user as { id: number }).id;
  const scootId = parseInt(req.params.id);
  if (isNaN(scootId)) return res.status(400).json({ ok: false, error: "invalid id" });

  const member = await db.query.scootMembers.findFirst({
    where: and(eq(scootMembers.scootId, scootId), eq(scootMembers.userId, userId)),
  });
  if (!member) return res.status(404).json({ ok: false, error: "not found" });

  const page = await db.query.scootPages.findFirst({
    where: and(eq(scootPages.scootId, scootId), eq(scootPages.slug, req.params.slug), eq(scootPages.published, true)),
  });
  if (!page) return res.status(404).json({ ok: false, error: "page not found" });

  const blocks = await db
    .select()
    .from(scootPageBlocks)
    .where(eq(scootPageBlocks.pageId, page.id))
    .orderBy(asc(scootPageBlocks.blockOrder));

  res.json({ ok: true, data: { ...page, blocks } });
});

export default router;

